              )}
              <div className="mt-20 pt-12 grid grid-cols-2 gap-24 text-center"><div className="space-y-2"><div className="border-t-2 border-slate-900 pt-3 text-[10px] font-black uppercase text-slate-900">{selectedEmployee.name}</div><p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest">Assinatura do Colaborador</p></div><div className="space-y-2"><div className="border-t-2 border-slate-900 pt-3 text-[10px] font-black uppercase text-slate-900">Administração Operacional</div><p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest">Assinatura Responsável</p></div></div>
           </div>
        </div>
      )}

      {showFinanceModal && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-md z-[2000] flex items-center justify-center p-4"><div className="bg-white rounded-[40px] w-full max-sm p-10 space-y-6 shadow-2xl animate-in zoom-in-95"><div className="text-center space-y-2"><div className="w-16 h-16 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center justify-center mx-auto mb-4"><CheckCircle2 size={32} /></div><h3 className="text-sm font-black uppercase text-slate-900">Gerar Saída Financeira?</h3><p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Deseja registrar este acerto como uma saída no caixa?</p></div><div className="space-y-4"><div className="space-y-1"><label className="text-[8px] font-black text-slate-400 uppercase ml-1 block">Título do Lançamento</label><input className="w-full bg-slate-50 border border-slate-200 p-4 rounded-2xl text-[10px] font-black uppercase" value={financeTitle} onChange={e => setFinanceTitle(e.target.value)} /></div><div className="space-y-1"><label className="text-[8px] font-black text-slate-400 uppercase ml-1 block">Categoria Financeira</label><select className="w-full bg-slate-50 border border-slate-200 p-4 rounded-2xl text-[10px] font-black uppercase" value={financeCategory} onChange={e => setFinanceCategory(e.target.value)}>{state.financeCategories.map(c => <option key={c} value={c}>{c.toUpperCase()}</option>)}</select></div><div className="p-4 bg-emerald-50 rounded-2xl border border-emerald-100 text-center"><p className="text-xl font-black text-emerald-600">{formatMoney(totalToPay)}</p><p className="text-[8px] font-black text-emerald-400 uppercase mt-1">Valor Total do Período</p></div><button onClick={handleCreateFinanceExit} disabled={isLoading} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black text-[10px] uppercase shadow-xl hover:bg-emerald-600 transition-all">{isLoading ? <Loader2 className="animate-spin mx-auto" size={16}/> : 'CONFIRMAR E QUITAR'}</button><button onClick={() => setShowFinanceModal(false)} className="w-full bg-slate-100 text-slate-400 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest">APENAS FECHAR</button></div></div></div>
