      if (error) return [];
      return data || [];
    } catch (e) {
      return [];
    }
  };

  const baseFilter = (q: any) => (!isMaster && companyId) ? q.eq('company_id', companyId) : q;

  const [areas, emps, inv, exits, flow, att, goals, companyInfo] = await Promise.all([
    safeQuery('areas', baseFilter(supabase.from('areas').select('*, services(*)').order('created_at', { ascending: false }))),
    safeQuery('employees', baseFilter(supabase.from('employees').select('*').order('name'))),
    safeQuery('inventory', baseFilter(supabase.from('inventory').select('*').order('name'))),
    safeQuery('inventory_exits', baseFilter(supabase.from('inventory_exits').select('*').order('date', { ascending: false }))),
    safeQuery('cash_flow', baseFilter(supabase.from('cash_flow').select('*').order('date', { ascending: false }))),
    safeQuery('attendance_records', baseFilter(supabase.from('attendance_records').select('*'))),
    safeQuery('monthly_goals', baseFilter(supabase.from('monthly_goals').select('*'))),
    companyId ? supabase.from('companies').select('*').eq('id', companyId).maybeSingle() : Promise.resolve({ data: null })
  ]);

  const goalsMap: Record<string, any> = {};
  (goals || []).forEach((g: any) => {
    goalsMap[g.month_key] = { 
      production: Number(g.production_goal || 0), 
      revenue: Number(g.revenue_goal || 0),
      inventory: Number(g.inventory_goal || 0),
      finance: Number(g.balance_goal || 0)
    };
  });

  const defaultRates = {
    [ServiceType.VARRICAO_KM]: 150.00,
    [ServiceType.CAPINA_MANUAL_M2]: 2.50,
    [ServiceType.ROCADA_MECANIZADA_M2]: 1.80,
    [ServiceType.ROCADA_TRATOR_M2]: 0.90,
    [ServiceType.BOCA_DE_LOBO]: 45.00,
    [ServiceType.PINTURA_MEIO_FIO]: 1.20,
  };

  const defaultServiceGoals = {
    [ServiceType.VARRICAO_KM]: 500,
    [ServiceType.CAPINA_MANUAL_M2]: 10000,
    [ServiceType.ROCADA_MECANIZADA_M2]: 20000,
    [ServiceType.ROCADA_TRATOR_M2]: 30000,
    [ServiceType.BOCA_DE_LOBO]: 100,
    [ServiceType.PINTURA_MEIO_FIO]: 5000,
  };

  const company = companyInfo?.data;

  return {
    company: company ? {
      id: company.id,
      name: company.name,
      cnpj: company.cnpj,
      phone: company.phone,
      address: company.address,
      email: company.email,
      website: company.website,
      plan: company.plan
    } : null,
    areas: areas.map((a: any) => ({
      id: a.id, 
      companyId: a.company_id, 
      name: a.name, 
      startDate: a.start_date, 
      endDate: a.end_date,
      startReference: a.start_reference, 
      endReference: a.end_reference, 
      observations: a.observations,
      status: a.status || 'executing',
      services: (a.services || []).map((s: any) => ({
        id: s.id, 
        companyId: s.company_id, 
        areaId: s.area_id, 
        type: s.type,
        areaM2: Number(s.area_m2), 
        unitValue: Number(s.unit_value), 
        totalValue: Number(s.total_value), 
        serviceDate: s.service_date
      }))
    })),
    employees: emps.map((e: any) => ({
      id: e.id, 
      companyId: e.company_id, 
      name: e.name, 
      role: e.role, 
      status: e.status || 'active',
      defaultValue: Number(e.default_value), 
      paymentModality: e.payment_modality || 'DIARIA',
      cpf: e.cpf, phone: e.phone, pixKey: e.pix_key, address: e.address,
      workload: e.workload,
      startTime: e.start_time,
      breakStart: e.break_start,
      breakEnd: e.break_end,
      endTime: e.end_time
    })),
    inventory: inv.map((i: any) => ({
      id: i.id, companyId: i.company_id, name: i.name, category: i.category,
      currentQty: Number(i.current_qty), minQty: Number(i.min_qty), idealQty: Number(i.ideal_qty || 0), unitValue: Number(i.unit_value || 0)
    })),
    inventoryExits: exits.map((ex: any) => ({
      id: ex.id, companyId: ex.company_id, itemId: ex.item_id, quantity: Number(ex.quantity), date: ex.date, destination: ex.destination, observation: ex.observation
    })),
    cashIn: flow.filter((f: any) => f.type === 'in').map((f: any) => ({ id: f.id, companyId: f.company_id, date: f.date, value: Number(f.value), reference: f.reference, type: f.type, category: f.category })),
    cashOut: flow.filter((f: any) => f.type === 'out').map((f: any) => ({ id: f.id, companyId: f.company_id, date: f.date, value: Number(f.value), type: f.type, category: f.category, reference: f.reference })),
    attendanceRecords: att.map((r: any) => ({
      id: r.id, 
      companyId: r.company_id, 
      employeeId: r.employee_id, 
      date: r.date, 
      status: r.status, 
      value: Number(r.value), 
      paymentStatus: r.payment_status,
      discountValue: Number(r.discount_value || 0), 
      discountObservation: r.discount_observation,
      clockIn: r.clock_in,
      breakStart: r.break_start,
      breakEnd: r.break_end,
      clockOut: r.clock_out
    })),
    monthlyGoals: goalsMap,
    serviceRates: company?.service_rates || defaultRates,
    serviceGoals: company?.service_goals || defaultServiceGoals,
    financeCategories: company?.finance_categories || ['Salários', 'Insumos', 'Manutenção', 'Impostos', 'Aluguel', 'Combustível'],
    inventoryCategories: company?.inventory_categories || ['Insumos', 'Equipamentos', 'Manutenção', 'EPIS'],
    employeeRoles: company?.employee_roles || ['Operador de Roçadeira', 'Ajudante Geral', 'Motorista', 'Encarregado']
  };
};

export const dbSave = async (table: string, data: any) => {
  const payload = camelToSnake(data);
  let query;

  if (payload.id) {
    const { id, ...updateData } = payload;
    query = supabase.from(table).update(updateData).eq('id', id);
  } else {
    if (table === 'monthly_goals') {
       query = supabase.from(table).upsert(payload, { onConflict: 'company_id, month_key' });
    } else {
       query = supabase.from(table).insert(payload);
    }
  }

  const { data: saved, error } = await query.select();
  if (error) {
    throw error;
  }
  return saved;
};

export const dbDelete = async (table: string, id: string) => {
  const { error } = await supabase.from(table).delete().eq('id', id);
  if (error) throw error;
};

export const signOut = async () => {
  try {
    await supabase.auth.signOut();
  } catch (e) {
    console.error("SignOut error:", e);
  } finally {
    localStorage.clear();
    sessionStorage.clear();
    window.location.href = '/';
  }
};

import React, { useState, useMemo } from 'react';
import { AppState, Employee, AttendanceRecord } from '../types';
import { Users, UserPlus, X, ChevronRight, ChevronLeft, Edit2, Trash2, Loader2, Save, Fingerprint, Smartphone, MapPin, CreditCard, Power, UserX, AlertCircle, Clock, Briefcase, HeartPulse, ShieldAlert, Palmtree } from 'lucide-react';
import { dbSave, dbDelete, fetchCompleteCompanyData } from '../lib/supabase';

interface EmployeesProps {
  state: AppState;
  setState: React.Dispatch<React.SetStateAction<AppState>>;
  notify: (msg: string, type?: 'success' | 'error') => void;
}

const Employees: React.FC<EmployeesProps> = ({ state, setState, notify }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [currentCalendarDate, setCurrentCalendarDate] = useState(new Date());
  const [showInactive, setShowInactive] = useState(true);
  const [showTimeModal, setShowTimeModal] = useState<{ emp: Employee, date: string, record?: AttendanceRecord } | null>(null);

  const initialFormState = { 
    name: '', 
    role: 'AJUDANTE GERAL', 
    defaultValue: '1600', 
    cpf: '', 
    phone: '', 
    pixKey: '', 
    address: '',
    paymentModality: 'CLT' as 'DIARIA' | 'CLT',
    workload: '44h Semanais',
    startTime: '08:00',
    breakStart: '12:00',
    breakEnd: '13:00',
    endTime: '17:00'
  };

  const [employeeForm, setEmployeeForm] = useState(initialFormState);

  const [pointForm, setPointForm] = useState({
    clockIn: '',
    breakStart: '',
    breakEnd: '',
    clockOut: '',
    status: 'present' as AttendanceRecord['status'],
    observation: ''
  });

  const refreshData = async () => {
    if (state.currentUser?.companyId) {
      const data = await fetchCompleteCompanyData(state.currentUser.companyId);
      if (data) setState(prev => ({ ...prev, ...data }));
    }
  };

  const handleToggleAttendance = async (empId: string, date: string) => {
    const emp = state.employees.find(e => e.id === empId);
    if (!emp) return;
    if (emp.status === 'inactive') return notify("Não é possível lançar frequência para inativos", "error");

    const existing = state.attendanceRecords.find(r => r.employeeId === empId && r.date === date);

    if (emp.paymentModality === 'CLT') {
      setPointForm({
        clockIn: existing?.clockIn || emp.startTime || '08:00',
        breakStart: existing?.breakStart || emp.breakStart || '12:00',
        breakEnd: existing?.breakEnd || emp.breakEnd || '13:00',
        clockOut: existing?.clockOut || emp.endTime || '17:00',
        status: existing?.status || 'present',
        observation: existing?.discountObservation || ''
      });
      setShowTimeModal({ emp, date, record: existing });
      return;
    }

    try {
      if (!existing) {
        await dbSave('attendance_records', {
          companyId: state.currentUser?.companyId,
          employee_id: empId,
          date,
          status: 'present',
          value: emp.defaultValue,
          payment_status: 'pendente'
        });
      } else if (existing.status === 'present') {
        await dbSave('attendance_records', { ...existing, status: 'partial', value: emp.defaultValue / 2 });
      } else if (existing.status === 'partial') {
        await dbSave('attendance_records', { ...existing, status: 'absent', value: 0 });
      } else if (existing.status === 'absent') {
        await dbSave('attendance_records', { ...existing, status: 'atestado', value: 0 });
      } else if (existing.status === 'atestado') {
        await dbSave('attendance_records', { ...existing, status: 'justified', value: 0 });
      } else {
        await dbDelete('attendance_records', existing.id);
      }
      await refreshData();
    } catch (e) { notify("Erro ao sincronizar presença", "error"); }
  };

  const handleSavePoint = async () => {
    if (!showTimeModal) return;
    const { emp, date, record } = showTimeModal;

    setIsLoading(true);
    try {
      await dbSave('attendance_records', {
        id: record?.id || undefined,
        companyId: state.currentUser?.companyId,
        employee_id: emp.id,
        date,
        status: pointForm.status,
        value: (pointForm.status === 'present' || pointForm.status === 'partial') ? emp.defaultValue : 0,
        payment_status: record?.paymentStatus || 'pendente',
        clock_in: (pointForm.status === 'present' || pointForm.status === 'partial') ? pointForm.clockIn : null,
        break_start: (pointForm.status === 'present' || pointForm.status === 'partial') ? pointForm.breakStart : null,
        break_end: (pointForm.status === 'present' || pointForm.status === 'partial') ? pointForm.breakEnd : null,
        clock_out: (pointForm.status === 'present' || pointForm.status === 'partial') ? pointForm.clockOut : null,
        discount_observation: pointForm.observation
      });
      await refreshData();
      setShowTimeModal(null);
      notify("Registro atualizado");
    } catch (e) {
      notify("Erro ao salvar registro", "error");
    } finally {
      setIsLoading(false);
    }
  };

  const handleToggleStatus = async (emp: Employee) => {
    setIsLoading(true);
    try {
      const newStatus = emp.status === 'active' ? 'inactive' : 'active';
      await dbSave('employees', { id: emp.id, status: newStatus });
      await refreshData();
      notify(`Colaborador ${newStatus === 'active' ? 'Reativado' : 'Inativado'}`);
    } catch (e) { notify("Falha ao atualizar status", "error"); } finally { setIsLoading(false); }
  };

  const handleSaveEmployee = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!employeeForm.name) return notify("Nome completo é obrigatório", "error");

    setIsLoading(true);
    try {
      await dbSave('employees', {
        id: editingId || undefined,
        companyId: state.currentUser?.companyId,
        name: employeeForm.name.toUpperCase(),
        role: employeeForm.role.toUpperCase(),
        defaultValue: parseFloat(employeeForm.defaultValue),
        cpf: employeeForm.cpf,
        phone: employeeForm.phone,
        pixKey: employeeForm.pixKey,
        address: employeeForm.address.toUpperCase(),
        status: editingId ? (state.employees.find(e => e.id === editingId)?.status || 'active') : 'active',
        paymentModality: employeeForm.paymentModality,
        workload: employeeForm.workload,
        startTime: employeeForm.startTime,
        breakStart: employeeForm.breakStart,
        breakEnd: employeeForm.breakEnd,
        endTime: employeeForm.endTime
