        case 'justified': return 'FJ';
        case 'vacation': return 'FE';
        case 'absent': return 'F';
        case 'partial': return 'P';
        default: return '-';
      }
    } else {
      switch(att.status) {
        case 'present': return 'P';
        case 'partial': return 'H';
        case 'absent': return 'F';
        case 'atestado': return 'AT';
        case 'justified': return 'FJ';
        default: return '-';
