                <div className="space-y-1">
                   <label className="text-[10px] font-black text-slate-400 uppercase ml-1 block">CPF</label>
                   <input required className="w-full bg-slate-50 border border-slate-200 p-4 rounded-2xl text-[10px] font-black outline-none focus:bg-white" placeholder="000.000.000-00" value={employeeForm.cpf} onChange={e => setEmployeeForm({...employeeForm, cpf: e.target.value})} />
                </div>

                <div className="space-y-1">
                   <label className="text-[10px] font-black text-slate-400 uppercase ml-1 block">Função / Cargo</label>
                   <select className="w-full bg-slate-50 border border-slate-200 p-4 rounded-2xl text-[10px] font-black uppercase" value={employeeForm.role} onChange={e => setEmployeeForm({...employeeForm, role: e.target.value})}>
                      {state.employeeRoles.map(r => <option key={r} value={r}>{r}</option>)}
                   </select>
                </div>

                <div className="space-y-1">
                   <label className="text-[10px] font-black text-slate-400 uppercase ml-1 block">Contato Telefônico</label>
                   <input className="w-full bg-slate-50 border border-slate-200 p-4 rounded-2xl text-[10px] font-black outline-none focus:bg-white" placeholder="(00) 00000-0000" value={employeeForm.phone} onChange={e => setEmployeeForm({...employeeForm, phone: e.target.value})} />
                </div>

                <div className="space-y-1">
                   <label className="text-[10px] font-black text-slate-400 uppercase ml-1 block">Chave PIX (Para Pagamento)</label>
                   <input className="w-full bg-slate-50 border border-slate-200 p-4 rounded-2xl text-[10px] font-black outline-none focus:bg-white" placeholder="CPF, E-mail ou Telefone" value={employeeForm.pixKey} onChange={e => setEmployeeForm({...employeeForm, pixKey: e.target.value})} />
                </div>

                <div className="md:col-span-2 space-y-1">
                   <label className="text-[10px] font-black text-slate-400 uppercase ml-1 block">Endereço de Residência</label>
                   <input className="w-full bg-slate-50 border border-slate-200 p-4 rounded-2xl text-[10px] font-black uppercase outline-none focus:bg-white" placeholder="RUA, NÚMERO, BAIRRO, CIDADE" value={employeeForm.address} onChange={e => setEmployeeForm({...employeeForm, address: e.target.value})} />
                </div>

                {/* Exibir Valor apenas para Diaristas */}
                {employeeForm.paymentModality === 'DIARIA' && (
                  <div className="md:col-span-2 space-y-1 bg-emerald-50/50 p-6 rounded-3xl border border-emerald-100">
                     <label className="text-[10px] font-black text-emerald-600 uppercase ml-1 block">Valor da Diária Padrão (R$)</label>
                     <input type="number" step="0.01" className="w-full bg-white border border-emerald-200 p-4 rounded-2xl text-lg font-black outline-none focus:border-emerald-500" value={employeeForm.defaultValue} onChange={e => setEmployeeForm({...employeeForm, defaultValue: e.target.value})} />
                  </div>
                )}

                <div className="md:col-span-2 p-6 bg-slate-50 rounded-[32px] border border-slate-200 space-y-6">
                  <div className="flex items-center gap-2 border-b border-slate-200 pb-3"><Clock size={16} className="text-slate-600" /><h4 className="text-[10px] font-black uppercase text-slate-600 tracking-widest">Definição de Jornada de Trabalho</h4></div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                     <div className="space-y-1">
                        <label className="text-[8px] font-black text-slate-400 uppercase ml-1 block">Carga Horária / Escala</label>
                        <input className="w-full bg-white border border-slate-200 p-3 rounded-xl text-[10px] font-black uppercase outline-none" placeholder="EX: 44H SEMANAIS" value={employeeForm.workload} onChange={e => setEmployeeForm({...employeeForm, workload: e.target.value})} />
                     </div>
                     <div className="grid grid-cols-4 gap-2">
                        <div className="space-y-1">
                           <label className="text-[8px] font-black text-slate-400 uppercase block text-center">Entrada</label>
                           <input type="time" className="w-full bg-white border border-slate-200 p-2.5 rounded-xl text-[9px] font-black outline-none" value={employeeForm.startTime} onChange={e => setEmployeeForm({...employeeForm, startTime: e.target.value})} />
                        </div>
                        <div className="space-y-1">
                           <label className="text-[8px] font-black text-slate-400 uppercase block text-center">S. Almoço</label>
                           <input type="time" className="w-full bg-white border border-slate-200 p-2.5 rounded-xl text-[9px] font-black outline-none" value={employeeForm.breakStart} onChange={e => setEmployeeForm({...employeeForm, breakStart: e.target.value})} />
                        </div>
                        <div className="space-y-1">
                           <label className="text-[8px] font-black text-slate-400 uppercase block text-center">R. Almoço</label>
                           <input type="time" className="w-full bg-white border border-slate-200 p-2.5 rounded-xl text-[9px] font-black outline-none" value={employeeForm.breakEnd} onChange={e => setEmployeeForm({...employeeForm, breakEnd: e.target.value})} />
                        </div>
                        <div className="space-y-1">
                           <label className="text-[8px] font-black text-slate-400 uppercase block text-center">Saída</label>
                           <input type="time" className="w-full bg-white border border-slate-200 p-2.5 rounded-xl text-[9px] font-black outline-none" value={employeeForm.endTime} onChange={e => setEmployeeForm({...employeeForm, endTime: e.target.value})} />
                        </div>
                     </div>
                  </div>
                </div>
              </div>

              <button disabled={isLoading} className="w-full bg-slate-900 text-white py-5 rounded-3xl font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-3 shadow-xl hover:bg-emerald-600 transition-all active:scale-95">
                {isLoading ? <Loader2 className="animate-spin" size={20} /> : <Save size={20}/>} {editingId ? 'ATUALIZAR CADASTRO' : 'FINALIZAR E INTEGRAR'}
              </button>
           </form>
        </div>
      )}

      {showTimeModal && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[300] flex items-center justify-center p-4">
           <div className="bg-white rounded-[40px] w-full max-w-sm p-8 space-y-6 shadow-2xl animate-in zoom-in-95 border border-slate-100">
              <div className="text-center">
                 <div className="w-14 h-14 bg-blue-50 text-blue-600 rounded-2xl flex items-center justify-center mx-auto mb-3"><Clock size={28} /></div>
                 <h3 className="text-[12px] font-black uppercase text-slate-900">Registro de Ocorrência</h3>
                 <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mt-1">{showTimeModal.emp.name} • {showTimeModal.date.split('-').reverse().join('/')}</p>
              </div>

              <div className="space-y-4">
                 <div className="space-y-1">
                    <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Tipo de Registro</label>
                    <select className="w-full bg-slate-50 border border-slate-200 p-4 rounded-2xl text-[10px] font-black uppercase outline-none focus:border-blue-500" value={pointForm.status} onChange={e => setPointForm({...pointForm, status: e.target.value as any})}>
                       <option value="present">Presença Integral</option>
                       <option value="partial">Atraso / Saída Antecipada</option>
                       <option value="atestado">Atestado Médico (Justificado)</option>
                       <option value="justified">Falta Justificada</option>
                       <option value="absent">Falta Injustificada</option>
                       <option value="vacation">Férias / Folga</option>
                    </select>
                 </div>

                 {(pointForm.status === 'present' || pointForm.status === 'partial') && (
                   <div className="space-y-3 animate-in fade-in zoom-in-95">
                      <div className="grid grid-cols-2 gap-3">
                        <div className="space-y-1">
                          <label className="text-[8px] font-black text-slate-400 uppercase ml-1">Entrada</label>
                          <input type="time" className="w-full bg-slate-50 border border-slate-200 p-3 rounded-xl text-[10px] font-black outline-none" value={pointForm.clockIn} onChange={e => setPointForm({...pointForm, clockIn: e.target.value})} />
                        </div>
                        <div className="space-y-1">
                          <label className="text-[8px] font-black text-slate-400 uppercase ml-1">S. Almoço</label>
                          <input type="time" className="w-full bg-slate-50 border border-slate-200 p-3 rounded-xl text-[10px] font-black outline-none" value={pointForm.breakStart} onChange={e => setPointForm({...pointForm, breakStart: e.target.value})} />
                        </div>
                      </div>
                      <div className="grid grid-cols-2 gap-3">
                        <div className="space-y-1">
                          <label className="text-[8px] font-black text-slate-400 uppercase ml-1">R. Almoço</label>
                          <input type="time" className="w-full bg-slate-50 border border-slate-200 p-3 rounded-xl text-[10px] font-black outline-none" value={pointForm.breakEnd} onChange={e => setPointForm({...pointForm, breakEnd: e.target.value})} />
                        </div>
                        <div className="space-y-1">
                          <label className="text-[8px] font-black text-slate-400 uppercase ml-1">Saída Final</label>
                          <input type="time" className="w-full bg-slate-50 border border-slate-200 p-3 rounded-xl text-[10px] font-black outline-none" value={pointForm.clockOut} onChange={e => setPointForm({...pointForm, clockOut: e.target.value})} />
                        </div>
                      </div>
                   </div>
                 )}

                 <div className="space-y-1">
                    <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Justificativa / Observação</label>
                    <textarea rows={3} className="w-full bg-slate-50 border border-slate-200 p-4 rounded-2xl text-[10px] font-black uppercase outline-none focus:border-blue-500 resize-none" placeholder="DESCREVA O MOTIVO..." value={pointForm.observation} onChange={e => setPointForm({...pointForm, observation: e.target.value})} />
                 </div>

                 <button onClick={handleSavePoint} disabled={isLoading} className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl hover:bg-slate-900 transition-all">
                    {isLoading ? <Loader2 className="animate-spin mx-auto" size={16}/> : 'CONFIRMAR REGISTRO'}
                 </button>
                 <button onClick={() => setShowTimeModal(null)} className="w-full bg-slate-100 text-slate-500 py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest">CANCELAR</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};
export default Employees;

import React, { useState, useMemo } from 'react';
import { AppState, AttendanceRecord } from '../types';
import { 
  Printer, Search, Calendar, FileText, User, Hash, Smartphone, Database, TableProperties,
  Users, DollarSign, Edit2, Save, Loader2, Clock, CheckCircle2, MapPin, X, ArrowRight
} from 'lucide-react';
import { dbSave, fetchCompleteCompanyData } from '../lib/supabase';

interface AnalyticsProps {
  state: AppState;
  setState: React.Dispatch<React.SetStateAction<AppState>>;
  notify: (msg: string, type?: 'success' | 'error') => void;
}

const Analytics: React.FC<AnalyticsProps> = ({ state, setState, notify }) => {
  const [selectedEmployeeId, setSelectedEmployeeId] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [showPrintView, setShowPrintView] = useState(false);
  const [editingRecordId, setEditingRecordId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const [editingValue, setEditingValue] = useState('');
  const [editingDiscount, setEditingDiscount] = useState('');
  const [editingObservation, setEditingObservation] = useState('');

  const [showFinanceModal, setShowFinanceModal] = useState(false);
  const [financeTitle, setFinanceTitle] = useState('');
  const [financeCategory, setFinanceCategory] = useState('');

  const [startDate, setStartDate] = useState(() => {
    const d = new Date();
    return new Date(d.getFullYear(), d.getMonth(), 1).toISOString().split('T')[0];
  });
  const [endDate, setEndDate] = useState(() => {
    const d = new Date();
    return new Date(d.getFullYear(), d.getMonth() + 1, 0).toISOString().split('T')[0];
  });

  const formatMoney = (value: number) => value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  const formatDate = (dateStr: string) => dateStr.split('-').reverse().join('/');
  const isWithinRange = (dateStr: string) => dateStr >= startDate && dateStr <= endDate;

  const downloadCSV = (filename: string, content: string) => {
    const blob = new Blob(["\ufeff" + content], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", `${filename}_${new Date().getTime()}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const exportInventory = () => {
    const headers = ["ID", "ITEM", "CATEGORIA", "QTD ATUAL", "VALOR UN", "TOTAL EM ESTOQUE"];
    const rows = state.inventory.map(i => [i.id, i.name, i.category, i.currentQty, i.unitValue, (i.currentQty * (i.unitValue || 0))]);
    const csvContent = [headers, ...rows].map(e => e.join(";")).join("\n");
    downloadCSV("Relatorio_Estoque", csvContent);
    notify("Planilha de estoque gerada!");
  };

  const exportEmployees = () => {
    const headers = ["ID", "NOME", "CARGO", "STATUS", "DIARIA PADRAO", "CPF", "MODALIDADE", "CARGA HORARIA"];
    const rows = state.employees.map(e => [e.id, e.name, e.role, e.status, e.defaultValue, e.cpf || "", e.paymentModality, e.workload || ""]);
    const csvContent = [headers, ...rows].map(e => e.join(";")).join("\n");
    downloadCSV("Relatorio_Equipe", csvContent);
    notify("Planilha de equipe gerada!");
  };

  const exportFinance = () => {
    const headers = ["DATA", "TIPO", "REFERENCIA", "CATEGORIA", "VALOR"];
    const rowsIn = state.cashIn.map(i => [i.date, "ENTRADA", i.reference, i.category, i.value]);
    const rowsOut = state.cashOut.map(o => [o.date, "SAIDA", o.reference, o.category, o.value]);
    const allRows = [...rowsIn, ...rowsOut].sort((a, b) => String(a[0]).localeCompare(String(b[0])));
    const csvContent = [headers, ...allRows].map(e => e.join(";")).join("\n");
    downloadCSV("Relatorio_Financeiro", csvContent);
    notify("Fluxo de caixa exportado!");
  };

  const exportProduction = () => {
    const headers = ["DATA", "O.S.", "TIPO SERVICO", "QUANTIDADE", "VALOR UN", "VALOR TOTAL"];
    const rows: any[] = [];
    state.areas.forEach(area => {
      (area.services || []).forEach(s => {
        rows.push([s.serviceDate, area.name, s.type, s.areaM2, s.unitValue, s.totalValue]);
      });
    });
    const csvContent = [headers, ...rows].sort((a, b) => String(a[0]).localeCompare(String(b[0]))).map(e => e.join(";")).join("\n");
    downloadCSV("Relatorio_Producao", csvContent);
    notify("Dados de produção exportados!");
  };

  const refreshData = async () => {
    if (state.currentUser?.companyId) {
      const data = await fetchCompleteCompanyData(state.currentUser.companyId);
      if (data) setState(prev => ({ ...prev, ...data }));
    }
  };

  const filteredEmployees = state.employees.filter(e => e.name.toLowerCase().includes(searchTerm.toLowerCase()));
  const selectedEmployee = state.employees.find(e => e.id === selectedEmployeeId);

  const attendanceHistory = useMemo(() => {
    return state.attendanceRecords
      .filter(r => r.employeeId === selectedEmployeeId && isWithinRange(r.date))
      .sort((a, b) => a.date.localeCompare(b.date));
  }, [state.attendanceRecords, selectedEmployeeId, startDate, endDate]);

  const totalBaseValue = attendanceHistory.reduce((acc, r) => acc + r.value, 0);
  const totalDiscounts = attendanceHistory.reduce((acc, r) => acc + (r.discountValue || 0), 0);
  const totalToPay = totalBaseValue - totalDiscounts;

  const handlePrint = () => {
    setShowPrintView(true);
    // Pequeno atraso para garantir que o modal de impressão esteja montado no DOM
    setTimeout(() => {
      window.print();
      // Após fechar o diálogo de impressão do navegador, verificamos se precisa abrir o modal financeiro
      if (selectedEmployee?.paymentModality !== 'CLT' && totalToPay > 0) {
        setFinanceTitle(`ACERTO: ${selectedEmployee?.name} - ${formatDate(startDate)} a ${formatDate(endDate)}`);
        setFinanceCategory('Salários');
        setShowFinanceModal(true);
      }
    }, 500);
  };

  const handleSaveValue = async (record: AttendanceRecord) => {
    const newVal = parseFloat(editingValue.replace(',', '.'));
    const newDiscount = parseFloat(editingDiscount.replace(',', '.'));

    setIsLoading(true);
    try {
      await dbSave('attendance_records', { 
        ...record, 
        value: isNaN(newVal) ? record.value : newVal,
        discountValue: isNaN(newDiscount) ? 0 : newDiscount,
        discountObservation: editingObservation
      });
      await refreshData();
      setEditingRecordId(null);
      notify("Alterações salvas!");
    } catch (e) { notify("Erro ao salvar", "error"); } finally { setIsLoading(false); }
  };

  const togglePaymentStatus = async (record: AttendanceRecord) => {
    setIsLoading(true);
    try {
      const newStatus = record.paymentStatus === 'pago' ? 'pendente' : 'pago';
      await dbSave('attendance_records', { ...record, paymentStatus: newStatus });
      await refreshData();
      notify(`Status alterado para ${newStatus.toUpperCase()}`);
    } catch (e) { notify("Erro ao alterar status", "error"); } finally { setIsLoading(false); }
  };

  const handleCreateFinanceExit = async () => {
    if (!selectedEmployee) return;

    setIsLoading(true);
    try {
      await dbSave('cash_flow', {
        companyId: state.currentUser?.companyId,
        type: 'out',
        value: totalToPay,
        date: new Date().toISOString().split('T')[0],
        reference: financeTitle || `ACERTO: ${selectedEmployee.name}`,
        category: financeCategory || 'Salários'
      });

      const updates = attendanceHistory.map(record => 
        dbSave('attendance_records', {
          ...record,
          paymentStatus: 'pago'
        })
      );

      await Promise.all(updates);
      await refreshData();
      setShowFinanceModal(false);
      notify("Saída financeira registrada e registros quitados!");
    } catch (e: any) {
      console.error("Erro ao registrar acerto:", e);
      notify("Falha ao registrar acerto financeiro.", "error");
    } finally {
      setIsLoading(false);
    }
  };

  const getStatusLabel = (status: AttendanceRecord['status']) => {
    switch(status) {
      case 'present': return 'PRESENÇA INTEGRAL';
      case 'partial': return 'HORÁRIO PARCIAL';
      case 'absent': return 'FALTA INJUSTIFICADA';
      case 'atestado': return 'ATESTADO MÉDICO';
      case 'justified': return 'FALTA JUSTIFICADA';
      case 'vacation': return 'FÉRIAS / FOLGA';
      default: return 'SEM REGISTRO';
    }
  };

  return (
    <div className="space-y-6">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4 print:hidden">
        <div>
          <h2 className="text-xl font-black text-slate-900 tracking-tight uppercase">Relatórios de Acerto</h2>
          <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest opacity-70">Geração de Fichas Financeiras Individuais</p>
        </div>
        <div className="flex items-center gap-2 bg-white border border-slate-200 p-2 rounded-xl shadow-sm">
          <Calendar size={14} className="text-slate-400" />
          <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="text-[10px] font-black uppercase bg-transparent outline-none" />
          <span className="text-slate-300">|</span>
          <input type="date" value={endDate} onChange={e => setEndDate(e.target.value)} className="text-[10px] font-black uppercase bg-transparent outline-none" />
        </div>
      </header>

      <section className="bg-slate-900 text-white rounded-[32px] p-6 shadow-2xl relative overflow-hidden print:hidden border border-white/5">
         <div className="relative z-10">
            <h3 className="text-[10px] font-black uppercase tracking-[0.2em] flex items-center gap-3 mb-5 opacity-70">
              <Database size={16} className="text-blue-400"/> Central de Dados e Exportação (CSV)
            </h3>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3">
               <button onClick={exportInventory} className="bg-white/5 border border-white/10 p-4 rounded-2xl flex items-center gap-4 transition-all hover:bg-blue-600 group">
                  <TableProperties size={18}/>
